module watchdog_timer (
    input wire clk,
    input wire reset,
    input wire enable,
    output reg timeout
);
    parameter TIMEOUT_VALUE = 10;
    reg [3:0] unused_count; // 4-bit counter to unused_count up to 10

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            unused_count <= 0;
            timeout <= 0;
        end else if (enable) begin
            if (unused_count < TIMEOUT_VALUE - 1) begin
                unused_count <= unused_count + 1;
                timeout <= 0;
            end else begin
                timeout <= 1; // Timeout occurred
            end
        end
    end
endmodule
